{
  "title": "Operating System Fundamentals Quiz",
  "difficulty": "medium",
  "questions": [
    {
      "id": "q1",
      "question": "What is the primary role of an Operating System according to the provided materials?",
      "options": {
        "A": "To perform specific tasks for the user",
        "B": "To act as an intermediary between the user and computer hardware",
        "C": "To replace the need for hardware interaction code",
        "D": "To serve as a hardware component for memory storage"
      },
      "answer": "B",
      "explanation": "The OS acts as an interface between the user and the computer hardware to manage resources."
    },
    {
      "id": "q2",
      "question": "Which term is used to describe the OS function of managing memory, devices, and files?",
      "options": {
        "A": "Abstraction",
        "B": "Isolation",
        "C": "Arbitration",
        "D": "Execution"
      },
      "answer": "C",
      "explanation": "Resource management is also known as arbitration in the context of OS functions."
    },
    {
      "id": "q3",
      "question": "How does 'Abstraction' benefit users and application developers?",
      "options": {
        "A": "It allows direct access to low-level hardware code",
        "B": "It increases the complexity of the application code base",
        "C": "It hides the underlying complexity of the hardware",
        "D": "It prevents the OS from managing software resources"
      },
      "answer": "C",
      "explanation": "Abstraction hides technical hardware complexities, providing a more convenient environment."
    },
    {
      "id": "q4",
      "question": "What is a specific consequence of not having an Operating System in a computer?",
      "options": {
        "A": "Applications would be less complex",
        "B": "There would be no memory protection",
        "C": "Resource exploitation would be impossible",
        "D": "System software would perform user tasks"
      },
      "answer": "B",
      "explanation": "Without an OS, the system lacks memory protection and applications become bulky and complex."
    },
    {
      "id": "q5",
      "question": "Where does the Operating System sit in the software hierarchy?",
      "options": {
        "A": "Between the hardware and application software",
        "B": "Above the application software level",
        "C": "Between the user and application software",
        "D": "Directly within the computer hardware"
      },
      "answer": "A",
      "explanation": "The OS serves as a platform sitting between the hardware and application software layers."
    },
    {
      "id": "q6",
      "question": "Which of these is considered a 'System Software' function?",
      "options": {
        "A": "Performing a specific task for the user",
        "B": "Controlling the computer system and providing a platform for apps",
        "C": "Acting as a user-specific word processor",
        "D": "Managing only hardware while ignoring software resources"
      },
      "answer": "B",
      "explanation": "System software operates and controls the system to provide a platform for application software."
    },
    {
      "id": "q7",
      "question": "According to the notes, how does the OS prevent applications from crashing the entire system?",
      "options": {
        "A": "By allowing applications to manage their own memory",
        "B": "By merging all application code into the hardware",
        "C": "By providing isolation and protection",
        "D": "By removing the abstraction layer"
      },
      "answer": "C",
      "explanation": "Isolation and protection prevent individual applications from interfering with others or the system."
    },
    {
      "id": "q8",
      "question": "What must be included in an application's code base if an Operating System is not present?",
      "options": {
        "A": "Arbitration logic for other users",
        "B": "Hardware interaction code",
        "C": "System software summaries",
        "D": "Memory protection algorithms for other apps"
      },
      "answer": "B",
      "explanation": "Without an OS, the hardware interaction code must be contained within the application itself."
    }
  ]
}
